import 'package:flutter_bloc/flutter_bloc.dart';

class SimpleBlocObserver extends BlocObserver {
  @override
  void onEvent(Bloc bloc, Object? event) {
    print('${bloc.runtimeType} event: $event');
    super.onEvent(bloc, event);
  }

  @override
  void onTransition(Bloc bloc, Transition transition) {
    print('${bloc.runtimeType} transition: $transition');
    super.onTransition(bloc, transition);
  }

  @override
  void onError(BlocBase bloc, Object error, StackTrace stackTrace) {
    print('${bloc.runtimeType} error: $error');
    super.onError(bloc, error, stackTrace);
  }
}

void main() {
  Bloc.observer = SimpleBlocObserver();
  runApp(MyApp());
}

import 'dart:developer' as developer;

class DevToolsBlocObserver extends BlocObserver {
  @override
  void onEvent(Bloc bloc, Object? event) {
    developer.log('$event', name: '${bloc.runtimeType}.event');
    super.onEvent(bloc, event);
  }

  @override
  void onTransition(Bloc bloc, Transition transition) {
    developer.log(
      '${transition.currentState} -> ${transition.nextState}',
      name: '${bloc.runtimeType}.transition',
    );
    super.onTransition(bloc, transition);
  }
}

class TimedBlocObserver extends BlocObserver {
  final Stopwatch _stopwatch = Stopwatch();

  @override
  void onEvent(Bloc bloc, Object? event) {
    _stopwatch.reset();
    _stopwatch.start();
    super.onEvent(bloc, event);
  }

  @override
  void onTransition(Bloc bloc, Transition transition) {
    _stopwatch.stop();
    print('${bloc.runtimeType} processed ${transition.event} in ${_stopwatch.elapsedMilliseconds}ms');
    super.onTransition(bloc, transition);
  }
}

import 'dart:developer' as developer;

class PerformanceBlocObserver extends BlocObserver {
  @override
  void onEvent(Bloc bloc, Object? event) {
    developer.Timeline.startSync('${bloc.runtimeType}.$event');
    super.onEvent(bloc, event);
  }

  @override
  void onTransition(Bloc bloc, Transition transition) {
    developer.Timeline.finishSync();
    super.onTransition(bloc, transition);
  }
}

