class MemoryLeakObserver extends BlocObserver {
  final _activeBlocs = <BlocBase>[];

  @override
  void onCreate(BlocBase bloc) {
    _activeBlocs.add(bloc);
    print('${bloc.runtimeType} created, active: ${_activeBlocs.length}');
    super.onCreate(bloc);
  }

  @override
  void onClose(BlocBase bloc) {
    _activeBlocs.remove(bloc);
    print('${bloc.runtimeType} closed, active: ${_activeBlocs.length}');
    super.onClose(bloc);
  }
}

